import "./Like.css"

function Like() {

  return (
    <div className="like-container" style={{minHeight: '100%', overflowY: 'auto'}}>
      {/* 헤더 */}
      <header className="like-header">
        <div className="like-header-content">
          <h1>발도장</h1>
          <h2>나의 발도장이 머물렀던 댕댕이들</h2>
        </div>
      </header>
      <div className="live-chat-message">발도장 페이지 아직 미완성</div>
    </div>
  )
}

export default Like
